import { Router } from 'express';
import { createPayment, deletePayment, getPaymentById, listPayments, updatePayment, } from '../controllers/payment.controller.js';
import { authenticate } from '../middleware/auth.middleware.js';
import { authorize } from '../middleware/authorize.middleware.js';
import { validateRequest } from '../middleware/validate.middleware.js';
import { createPaymentValidator, listPaymentsValidator, paymentIdValidator, updatePaymentValidator, } from '../validators/payment.validator.js';
export const paymentRouter = Router();
paymentRouter.get('/', authenticate, listPaymentsValidator, validateRequest, listPayments);
paymentRouter.post('/', authenticate, authorize('super_admin', 'admin', 'manager'), createPaymentValidator, validateRequest, createPayment);
paymentRouter.get('/:id', authenticate, paymentIdValidator, validateRequest, getPaymentById);
paymentRouter.patch('/:id', authenticate, authorize('super_admin', 'admin', 'manager'), updatePaymentValidator, validateRequest, updatePayment);
paymentRouter.delete('/:id', authenticate, authorize('super_admin', 'admin'), paymentIdValidator, validateRequest, deletePayment);
